59	pub async fn register(data: &RegisterData) -> Result<UserInfo, String> {
60	    let resp: LoginResponse = api::post("/api/auth/provision", data).await?;
61	
62	    LocalStorage::set("auth_token", &resp.token).map_err(|e| e.to_string())?;
63	    LocalStorage::set("current_user", &resp.user).map_err(|e| e.to_string())?;
64	
65	    Ok(resp.user)
66	}
