72	pub fn get_token() -> Option<String> {
73	    LocalStorage::get::<String>("auth_token").ok()
74	}
75	
76	pub fn logout() {
77	    let _ = LocalStorage::delete("auth_token");
78	    let _ = LocalStorage::delete("current_user");
79	}
80	
81	pub fn is_authenticated() -> bool {
82	    get_token().is_some()
83	}
