15	fn generate_token(user_id: &str, username: &str, role: &str, session_id: &str) -> Result<String, Status> {
16	    let jwt_secret = std::env::var("JWT_SECRET")
17	        .expect("JWT_SECRET environment variable must be set");
18	    let expiry_hours: u64 = std::env::var("TOKEN_EXPIRY_HOURS")
19	        .ok()
20	        .and_then(|v| v.parse().ok())
21	        .unwrap_or(24);
22	
23	    let now = Utc::now().timestamp() as usize;
24	    let claims = Claims {
25	        sub: user_id.to_string(),
26	        username: username.to_string(),
27	        role: role.to_string(),
28	        iat: now,
29	        exp: now + (expiry_hours as usize * 3600),
30	        session_id: session_id.to_string(),
31	    };
32	
33	    encode(
34	        &Header::default(),
35	        &claims,
36	        &EncodingKey::from_secret(jwt_secret.as_bytes()),
37	    )
38	    .map_err(|_| Status::InternalServerError)
39	}
