41	async fn create_session(pool: &DbPool, user_id: &str, token: &str) -> Result<String, Status> {
42	    let session_id = Uuid::new_v4().to_string();
43	    let now = Utc::now().naive_utc();
44	    let expires = now + Duration::minutes(models::SESSION_IDLE_TIMEOUT_MINUTES);
45	
46	    sqlx::query(
47	        "INSERT INTO sessions (id, user_id, token, last_activity, expires_at, is_active) VALUES (?, ?, ?, ?, ?, true)"
48	    )
49	    .bind(&session_id)
50	    .bind(user_id)
51	    .bind(token)
52	    .bind(now)
53	    .bind(expires)
54	    .execute(pool)
55	    .await
56	    .map_err(|_| Status::InternalServerError)?;
57	
58	    Ok(session_id)
59	}
