75	#[post("/login", data = "<req>")]
76	pub async fn login(pool: &State<DbPool>, req: Json<LoginRequest>) -> Result<Json<LoginResponse>, Status> {
77	    let row = sqlx::query_as::<_, (String, String, String, String, String, String, Option<String>, String, bool, Option<String>, bool, bool, bool, bool)>(
78	        "SELECT id, username, email, password_hash, first_name, last_name, contact_info, role, is_active, invoice_title, notify_submissions, notify_orders, notify_reviews, notify_cases FROM users WHERE username = ? AND is_active = true AND soft_deleted_at IS NULL"
79	    )
80	    .bind(&req.username)
81	    .fetch_optional(pool.inner())
82	    .await
83	    .map_err(|_| Status::InternalServerError)?;
84	
85	    match row {
86	        Some((id, username, email, password_hash, first_name, last_name, contact_info, role, is_active, invoice_title, ns, no, nr, nc)) => {
87	            let password = req.password.clone();
88	            let hash_clone = password_hash.clone();
89	            let valid = tokio::task::spawn_blocking(move || {
90	                verify(&password, &hash_clone).unwrap_or(false)
91	            }).await.unwrap_or(false);
92	            if !valid {
93	                log_audit(pool.inner(), Some(&id), "login_failed", Some("user"), Some(&id), Some("Invalid password")).await;
94	                return Err(Status::Unauthorized);
95	            }
96	
97	            // Create session
98	            let session_id = Uuid::new_v4().to_string();
99	            let token = generate_token(&id, &username, &role, &session_id)?;
100	            let now = Utc::now().naive_utc();
101	            let expires = now + Duration::minutes(models::SESSION_IDLE_TIMEOUT_MINUTES);
102	
103	            let _ = sqlx::query(
104	                "INSERT INTO sessions (id, user_id, token, last_activity, expires_at, is_active) VALUES (?, ?, ?, ?, ?, true)"
105	            )
106	            .bind(&session_id)
107	            .bind(&id)
108	            .bind(&token)
109	            .bind(now)
110	            .bind(expires)
111	            .execute(pool.inner())
112	            .await;
113	
114	            log_audit(pool.inner(), Some(&id), "login_success", Some("user"), Some(&id), None).await;
115	
116	            Ok(Json(LoginResponse {
117	                token,
118	                user: UserResponse {
119	                    id, username, email, first_name, last_name, contact_info, role, is_active,
120	                    invoice_title, notify_submissions: ns, notify_orders: no, notify_reviews: nr,
121	                    notify_cases: nc, created_at: None,
122	                },
123	            }))
124	        }
125	        None => Err(Status::Unauthorized),
126	    }
127	}
