129	/// Admin-provisioned account creation — no public self-registration.
130	#[post("/provision", data = "<req>")]
131	pub async fn register(pool: &State<DbPool>, admin: AuthenticatedUser, req: Json<crate::models::user::CreateUserRequest>) -> Result<Json<LoginResponse>, Status> {
132	    // Only administrators can provision new accounts
133	    admin.require_permission("admin.provision_users")?;
134	
135	    let existing = sqlx::query_scalar::<_, i64>("SELECT COUNT(*) FROM users WHERE email = ? OR username = ?")
136	        .bind(&req.email)
137	        .bind(&req.username)
138	        .fetch_one(pool.inner())
139	        .await
140	        .map_err(|_| Status::InternalServerError)?;
141	
142	    if existing > 0 {
143	        return Err(Status::Conflict);
144	    }
145	
146	    let valid_roles = ["student", "instructor", "academic_staff", "administrator"];
147	    if !valid_roles.contains(&req.role.as_str()) {
148	        return Err(Status::BadRequest);
149	    }
150	
151	    let id = Uuid::new_v4().to_string();
152	    let new_pass = req.password.clone();
153	    let password_hash = tokio::task::spawn_blocking(move || {
154	        hash(&new_pass, DEFAULT_COST)
155	    }).await.map_err(|_| Status::InternalServerError)?.map_err(|_| Status::InternalServerError)?;
156	
157	    sqlx::query(
158	        "INSERT INTO users (id, username, email, password_hash, first_name, last_name, role, is_active, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, true, NOW(), NOW())"
159	    )
160	    .bind(&id)
161	    .bind(&req.username)
162	    .bind(&req.email)
163	    .bind(&password_hash)
164	    .bind(&req.first_name)
165	    .bind(&req.last_name)
166	    .bind(&req.role)
167	    .execute(pool.inner())
168	    .await
169	    .map_err(|_| Status::InternalServerError)?;
170	
171	    let session_id = Uuid::new_v4().to_string();
172	    let token = generate_token(&id, &req.username, &req.role, &session_id)?;
173	
174	    let now = Utc::now().naive_utc();
175	    let expires = now + Duration::minutes(models::SESSION_IDLE_TIMEOUT_MINUTES);
176	    let _ = sqlx::query(
177	        "INSERT INTO sessions (id, user_id, token, last_activity, expires_at, is_active) VALUES (?, ?, ?, ?, ?, true)"
178	    )
179	    .bind(&session_id)
180	    .bind(&id)
181	    .bind(&token)
182	    .bind(now)
183	    .bind(expires)
184	    .execute(pool.inner())
185	    .await;
186	
187	    log_audit(pool.inner(), Some(&admin.user_id), "user_provisioned", Some("user"), Some(&id),
188	        Some(&format!("Account '{}' provisioned by admin '{}'", req.username, admin.username))).await;
189	
190	    Ok(Json(LoginResponse {
191	        token,
192	        user: UserResponse {
193	            id, username: req.username.clone(), email: req.email.clone(),
194	            first_name: req.first_name.clone(), last_name: req.last_name.clone(),
195	            contact_info: None, role: req.role.clone(), is_active: true,
196	            invoice_title: None, notify_submissions: true, notify_orders: true,
197	            notify_reviews: true, notify_cases: true, created_at: None,
198	        },
199	    }))
200	}
