224	#[post("/change-password", data = "<req>")]
225	pub async fn change_password(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<ChangePasswordRequest>) -> Result<Status, Status> {
226	    let row = sqlx::query_scalar::<_, String>("SELECT password_hash FROM users WHERE id = ?")
227	        .bind(&user.user_id)
228	        .fetch_optional(pool.inner())
229	        .await
230	        .map_err(|_| Status::InternalServerError)?;
231	
232	    match row {
233	        Some(current_hash) => {
234	            let current_password = req.current_password.clone();
235	            let valid = tokio::task::spawn_blocking(move || {
236	                verify(&current_password, &current_hash).unwrap_or(false)
237	            }).await.unwrap_or(false);
238	            if !valid {
239	                return Err(Status::Unauthorized);
240	            }
241	            let new_password = req.new_password.clone();
242	            let new_hash = tokio::task::spawn_blocking(move || {
243	                hash(&new_password, DEFAULT_COST)
244	            }).await.map_err(|_| Status::InternalServerError)?.map_err(|_| Status::InternalServerError)?;
245	            sqlx::query("UPDATE users SET password_hash = ?, updated_at = NOW() WHERE id = ?")
246	                .bind(&new_hash)
247	                .bind(&user.user_id)
248	                .execute(pool.inner())
249	                .await
250	                .map_err(|_| Status::InternalServerError)?;
251	            log_audit(pool.inner(), Some(&user.user_id), "password_changed", Some("user"), Some(&user.user_id), None).await;
252	            Ok(Status::Ok)
253	        }
254	        None => Err(Status::NotFound),
255	    }
256	}
