258	#[post("/generate-reset-token", data = "<req>")]
259	pub async fn generate_reset_token(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<GenerateResetTokenRequest>) -> Result<Json<ResetTokenResponse>, Status> {
260	    user.require_permission("auth.generate_reset")?;
261	
262	    // Generate random token using UUID (Send-safe)
263	    let token = format!("{}{}", Uuid::new_v4().to_string().replace('-', ""), &Uuid::new_v4().to_string().replace('-', "")[..16]);
264	    let token_id = Uuid::new_v4().to_string();
265	    let expires = Utc::now().naive_utc() + Duration::minutes(models::PASSWORD_RESET_EXPIRY_MINUTES);
266	
267	    sqlx::query(
268	        "INSERT INTO password_reset_tokens (id, user_id, token, used, expires_at, created_by, created_at) VALUES (?, ?, ?, false, ?, ?, NOW())"
269	    )
270	    .bind(&token_id)
271	    .bind(&req.user_id)
272	    .bind(&token)
273	    .bind(&expires)
274	    .bind(&user.user_id)
275	    .execute(pool.inner())
276	    .await
277	    .map_err(|_| Status::InternalServerError)?;
278	
279	    log_audit(pool.inner(), Some(&user.user_id), "reset_token_generated", Some("user"), Some(&req.user_id), Some("Password reset token generated by admin")).await;
280	
281	    Ok(Json(ResetTokenResponse {
282	        token,
283	        expires_at: expires.format("%m/%d/%Y, %I:%M:%S %p").to_string(),
284	    }))
285	}
