287	#[post("/use-reset-token", data = "<req>")]
288	pub async fn use_reset_token(pool: &State<DbPool>, req: Json<UseResetTokenRequest>) -> Result<Status, Status> {
289	    let row = sqlx::query_as::<_, (String, String, bool, chrono::NaiveDateTime)>(
290	        "SELECT id, user_id, used, expires_at FROM password_reset_tokens WHERE token = ?"
291	    )
292	    .bind(&req.token)
293	    .fetch_optional(pool.inner())
294	    .await
295	    .map_err(|_| Status::InternalServerError)?;
296	
297	    match row {
298	        Some((token_id, user_id, used, expires_at)) => {
299	            if used {
300	                return Err(Status::Gone);
301	            }
302	            if Utc::now().naive_utc() > expires_at {
303	                return Err(Status::Gone);
304	            }
305	
306	            let new_password = req.new_password.clone();
307	            let new_hash = tokio::task::spawn_blocking(move || {
308	                hash(&new_password, DEFAULT_COST)
309	            }).await.map_err(|_| Status::InternalServerError)?.map_err(|_| Status::InternalServerError)?;
310	
311	            sqlx::query("UPDATE users SET password_hash = ?, updated_at = NOW() WHERE id = ?")
312	                .bind(&new_hash)
313	                .bind(&user_id)
314	                .execute(pool.inner())
315	                .await
316	                .map_err(|_| Status::InternalServerError)?;
317	
318	            sqlx::query("UPDATE password_reset_tokens SET used = true WHERE id = ?")
319	                .bind(&token_id)
320	                .execute(pool.inner())
321	                .await
322	                .map_err(|_| Status::InternalServerError)?;
323	
324	            log_audit(pool.inner(), Some(&user_id), "password_reset_used", Some("user"), Some(&user_id), None).await;
325	            Ok(Status::Ok)
326	        }
327	        None => Err(Status::NotFound),
328	    }
329	}
