360	#[get("/export-my-data")]
361	pub async fn export_my_data(pool: &State<DbPool>, user: AuthenticatedUser) -> Result<(rocket::http::ContentType, Vec<u8>), Status> {
362	    // User profile
363	    let profile = sqlx::query_as::<_, (String, String, String, String, String, Option<String>, String)>(
364	        "SELECT id, username, email, first_name, last_name, contact_info, role FROM users WHERE id = ?"
365	    )
366	    .bind(&user.user_id)
367	    .fetch_optional(pool.inner())
368	    .await
369	    .map_err(|_| Status::InternalServerError)?;
370	
371	    let profile_json = match profile {
372	        Some((id, username, email, fn_, ln, ci, role)) => serde_json::json!({
373	            "id": id, "username": username, "email": email,
374	            "first_name": fn_, "last_name": ln, "contact_info": ci, "role": role
375	        }),
376	        None => return Err(Status::NotFound),
377	    };
378	
379	    // Addresses
380	    let addrs = sqlx::query_as::<_, (String, String, String, Option<String>, String, String, String, bool)>(
381	        "SELECT id, label, street_line1, street_line2, city, state, zip_code, is_default FROM user_addresses WHERE user_id = ?"
382	    )
383	    .bind(&user.user_id)
384	    .fetch_all(pool.inner())
385	    .await
386	    .map_err(|_| Status::InternalServerError)?;
387	
388	    let addresses: Vec<serde_json::Value> = addrs.into_iter().map(|(id, label, s1, s2, city, state, zip, def)| {
389	        serde_json::json!({"id": id, "label": label, "street_line1": s1, "street_line2": s2, "city": city, "state": state, "zip_code": zip, "is_default": def})
390	    }).collect();
391	
392	    // Submissions
393	    let subs = sqlx::query_as::<_, (String, String, String, String)>(
394	        "SELECT id, title, submission_type, status FROM submissions WHERE author_id = ?"
395	    )
396	    .bind(&user.user_id)
397	    .fetch_all(pool.inner())
398	    .await
399	    .map_err(|_| Status::InternalServerError)?;
400	
401	    let submissions: Vec<serde_json::Value> = subs.into_iter().map(|(id, title, st, status)| {
402	        serde_json::json!({"id": id, "title": title, "submission_type": st, "status": status})
403	    }).collect();
404	
405	    // Orders
406	    let ords = sqlx::query_as::<_, (String, String, String, String, f64)>(
407	        "SELECT id, order_number, subscription_period, status, total_amount FROM orders WHERE user_id = ?"
408	    )
409	    .bind(&user.user_id)
410	    .fetch_all(pool.inner())
411	    .await
