18	#[post("/", data = "<req>")]
19	pub async fn create_order(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<CreateOrderRequest>) -> Result<Json<OrderWithItems>, Status> {
20	    let valid_periods = ["monthly", "quarterly", "annual"];
21	    if !valid_periods.contains(&req.subscription_period.as_str()) {
22	        return Err(Status::BadRequest);
23	    }
24	    if req.line_items.is_empty() {
25	        return Err(Status::BadRequest);
26	    }
27	
28	    let order_id = Uuid::new_v4().to_string();
29	    let order_number = generate_order_number();
30	
31	    // Validate shipping_address_id ownership if provided
32	    if let Some(ref addr_id) = req.shipping_address_id {
33	        let addr_owner = sqlx::query_scalar::<_, String>(
34	            "SELECT user_id FROM user_addresses WHERE id = ?"
35	        )
36	        .bind(addr_id)
37	        .fetch_optional(pool.inner())
38	        .await
39	        .map_err(|_| Status::InternalServerError)?;
40	
41	        match addr_owner {
42	            Some(owner_id) => {
43	                if owner_id != user.user_id {
44	                    return Err(Status::Forbidden);
45	                }
46	            }
47	            None => return Err(Status::NotFound),
48	        }
49	    }
50	
51	    let mut total_amount: f64 = 0.0;
52	    let mut has_high_qty = false;
53	    let mut line_items_out = Vec::new();
54	
55	    // Calculate totals first without inserting
56	    for item in &req.line_items {
57	        let line_total = item.quantity as f64 * item.unit_price;
58	        total_amount += line_total;
59	        if item.quantity > models::HIGH_QUANTITY_THRESHOLD {
60	            has_high_qty = true;
61	        }
62	    }
63	
64	    // Check for repeated refunds
65	    let refund_count = sqlx::query_scalar::<_, i64>(
66	        "SELECT COUNT(*) FROM payments WHERE order_id IN (SELECT id FROM orders WHERE user_id = ?) AND transaction_type = 'refund'"
67	    )
68	    .bind(&user.user_id)
69	    .fetch_one(pool.inner())
70	    .await
71	    .unwrap_or(0);
72	
73	    let is_flagged = has_high_qty || refund_count >= models::REFUND_COUNT_THRESHOLD;
74	    let flag_reason = if has_high_qty && refund_count >= models::REFUND_COUNT_THRESHOLD {
75	        Some("High quantity order AND repeated refund history".to_string())
76	    } else if has_high_qty {
77	        Some("Unusually high quantity order".to_string())
78	    } else if refund_count >= models::REFUND_COUNT_THRESHOLD {
79	        Some("Account with repeated refund requests".to_string())
80	    } else {
81	        None
82	    };
83	
84	    // Insert order FIRST so FK on line items is satisfied
85	    sqlx::query(
86	        "INSERT INTO orders (id, user_id, order_number, subscription_period, shipping_address_id, status, payment_status, total_amount, is_flagged, flag_reason, created_at, updated_at) VALUES (?, ?, ?, ?, ?, 'pending', 'unpaid', ?, ?, ?, NOW(), NOW())"
87	    )
88	    .bind(&order_id).bind(&user.user_id).bind(&order_number).bind(&req.subscription_period)
89	    .bind(&req.shipping_address_id).bind(total_amount).bind(is_flagged).bind(&flag_reason)
90	    .execute(pool.inner())
91	    .await
92	    .map_err(|_| Status::InternalServerError)?;
93	
94	    // Now insert line items
95	    for item in &req.line_items {
96	        let line_total = item.quantity as f64 * item.unit_price;
97	        let li_id = Uuid::new_v4().to_string();
98	        sqlx::query(
99	            "INSERT INTO order_line_items (id, order_id, publication_title, series_name, quantity, unit_price, line_total) VALUES (?, ?, ?, ?, ?, ?, ?)"
100	        )
101	        .bind(&li_id).bind(&order_id).bind(&item.publication_title).bind(&item.series_name)
102	        .bind(item.quantity).bind(item.unit_price).bind(line_total)
103	        .execute(pool.inner())
104	        .await
105	        .map_err(|_| Status::InternalServerError)?;
106	
107	        line_items_out.push(OrderLineItem {
108	            id: li_id, order_id: order_id.clone(), publication_title: item.publication_title.clone(),
109	            series_name: item.series_name.clone(), quantity: item.quantity, unit_price: item.unit_price, line_total,
110	        });
111	    }
112	
113	    if is_flagged {
114	        let _ = sqlx::query(
115	            "INSERT INTO abnormal_order_flags (id, order_id, user_id, flag_type, reason, created_at) VALUES (?, ?, ?, ?, ?, NOW())"
116	        )
117	        .bind(Uuid::new_v4().to_string()).bind(&order_id).bind(&user.user_id)
118	        .bind(if has_high_qty { "high_quantity" } else { "repeated_refunds" })
119	        .bind(flag_reason.as_deref().unwrap_or(""))
120	        .execute(pool.inner()).await;
121	    }
122	
123	    let order = Order {
124	        id: order_id, user_id: user.user_id, order_number, subscription_period: req.subscription_period.clone(),
125	        shipping_address_id: req.shipping_address_id.clone(), status: "pending".to_string(),
126	        payment_status: "unpaid".to_string(), total_amount, parent_order_id: None,
127	        is_flagged, flag_reason, created_at: None, updated_at: None,
128	    };
129	
130	    Ok(Json(OrderWithItems { order, line_items: line_items_out }))
131	}
