134	pub async fn list_orders(pool: &State<DbPool>, user: AuthenticatedUser) -> Result<Json<Vec<Order>>, Status> {
135	    let base = "SELECT id, user_id, order_number, subscription_period, shipping_address_id, status, payment_status, CAST(total_amount AS DOUBLE), parent_order_id, is_flagged, flag_reason, created_at, updated_at FROM orders";
136	
137	    let rows = if user.is_privileged() {
138	        sqlx::query_as::<_, (String, String, String, String, Option<String>, String, String, f64, Option<String>, bool, Option<String>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
139	            &format!("{} ORDER BY created_at DESC", base)
140	        )
141	        .fetch_all(pool.inner()).await
142	    } else {
143	        sqlx::query_as::<_, (String, String, String, String, Option<String>, String, String, f64, Option<String>, bool, Option<String>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
144	            &format!("{} WHERE user_id = ? ORDER BY created_at DESC", base)
145	        )
146	        .bind(&user.user_id)
147	        .fetch_all(pool.inner()).await
148	    }.map_err(|_| Status::InternalServerError)?;
