214	/// Split order by series: creates new orders per unique series
215	#[post("/split", data = "<req>")]
216	pub async fn split_order(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<SplitOrderRequest>) -> Result<Json<Vec<Order>>, Status> {
217	    user.require_permission("orders.manage")?;
218	
219	    // Get original order
220	    let orig = sqlx::query_as::<_, (String, String, String, Option<String>)>(
221	        "SELECT id, user_id, subscription_period, shipping_address_id FROM orders WHERE id = ?"
222	    )
223	    .bind(&req.order_id).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
224	
225	    let (orig_id, orig_user, orig_period, orig_addr) = match orig {
226	        Some(o) => o,
227	        None => return Err(Status::NotFound),
228	    };
229	
230	    // Get line items grouped by series
231	    let items = sqlx::query_as::<_, (String, String, Option<String>, i32, f64, f64)>(
232	        "SELECT id, publication_title, series_name, quantity, CAST(unit_price AS DOUBLE), CAST(line_total AS DOUBLE) FROM order_line_items WHERE order_id = ?"
233	    )
234	    .bind(&orig_id).fetch_all(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
235	
236	    let mut series_map: std::collections::HashMap<String, Vec<(String, String, Option<String>, i32, f64, f64)>> = std::collections::HashMap::new();
237	    for item in items {
238	        let series = item.2.clone().unwrap_or_else(|| "default".to_string());
239	        series_map.entry(series).or_default().push(item);
240	    }
241	
242	    if series_map.len() <= 1 {
243	        return Err(Status::BadRequest); // Nothing to split
244	    }
245	
246	    let mut new_orders = Vec::new();
247	
248	    for (_series, items) in &series_map {
249	        let new_id = Uuid::new_v4().to_string();
250	        let new_number = generate_order_number();
251	        let total: f64 = items.iter().map(|i| i.5).sum();
252	
253	        sqlx::query(
254	            "INSERT INTO orders (id, user_id, order_number, subscription_period, shipping_address_id, status, payment_status, total_amount, parent_order_id, is_flagged, created_at, updated_at) VALUES (?, ?, ?, ?, ?, 'pending', 'unpaid', ?, ?, false, NOW(), NOW())"
255	        )
256	        .bind(&new_id).bind(&orig_user).bind(&new_number).bind(&orig_period).bind(&orig_addr)
257	        .bind(total).bind(&orig_id)
258	        .execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
259	
260	        for item in items {
261	            let li_id = Uuid::new_v4().to_string();
262	            sqlx::query(
263	                "INSERT INTO order_line_items (id, order_id, publication_title, series_name, quantity, unit_price, line_total) VALUES (?, ?, ?, ?, ?, ?, ?)"
264	            )
265	            .bind(&li_id).bind(&new_id).bind(&item.1).bind(&item.2).bind(item.3).bind(item.4).bind(item.5)
266	            .execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
267	        }
268	
269	        new_orders.push(Order {
270	            id: new_id, user_id: orig_user.clone(), order_number: new_number,
271	            subscription_period: orig_period.clone(), shipping_address_id: orig_addr.clone(),
272	            status: "pending".to_string(), payment_status: "unpaid".to_string(),
273	            total_amount: total, parent_order_id: Some(orig_id.clone()),
274	            is_flagged: false, flag_reason: None, created_at: None, updated_at: None,
275	        });
276	    }
277	
278	    // Mark original as split
279	    sqlx::query("UPDATE orders SET status = 'split', updated_at = NOW() WHERE id = ?")
280	        .bind(&orig_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
281	
282	    Ok(Json(new_orders))
283	}
