285	/// Merge multiple orders from same user into one
286	#[post("/merge", data = "<req>")]
287	pub async fn merge_orders(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<MergeOrdersRequest>) -> Result<Json<OrderWithItems>, Status> {
288	    user.require_permission("orders.manage")?;
289	    if req.order_ids.len() < 2 {
290	        return Err(Status::BadRequest);
291	    }
292	
293	    // Verify all orders belong to same user
294	    let mut owner_id: Option<String> = None;
295	    let mut period: Option<String> = None;
296	    let mut addr: Option<String> = None;
297	
298	    for oid in &req.order_ids {
299	        let row = sqlx::query_as::<_, (String, String, Option<String>)>(
300	            "SELECT user_id, subscription_period, shipping_address_id FROM orders WHERE id = ?"
301	        )
302	        .bind(oid).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
303	
304	        match row {
305	            Some((uid, sp, sa)) => {
306	                if let Some(ref existing) = owner_id {
307	                    if existing != &uid { return Err(Status::BadRequest); }
308	                } else {
309	                    owner_id = Some(uid);
310	                    period = Some(sp);
311	                    addr = sa;
312	                }
313	            }
314	            None => return Err(Status::NotFound),
315	        }
316	    }
317	
318	    let merged_id = Uuid::new_v4().to_string();
319	    let merged_number = generate_order_number();
320	    let mut all_items = Vec::new();
321	    let mut total = 0.0_f64;
322	
323	    for oid in &req.order_ids {
324	        let items = sqlx::query_as::<_, (String, Option<String>, i32, f64, f64)>(
325	            "SELECT publication_title, series_name, quantity, CAST(unit_price AS DOUBLE), CAST(line_total AS DOUBLE) FROM order_line_items WHERE order_id = ?"
326	        )
327	        .bind(oid).fetch_all(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
328	
329	        for (pt, sn, qty, up, lt) in items {
330	            total += lt;
331	            let li_id = Uuid::new_v4().to_string();
332	            all_items.push(OrderLineItem {
333	                id: li_id.clone(), order_id: merged_id.clone(), publication_title: pt.clone(),
334	                series_name: sn.clone(), quantity: qty, unit_price: up, line_total: lt,
335	            });
336	        }
337	    }
338	
339	    sqlx::query(
340	        "INSERT INTO orders (id, user_id, order_number, subscription_period, shipping_address_id, status, payment_status, total_amount, is_flagged, created_at, updated_at) VALUES (?, ?, ?, ?, ?, 'pending', 'unpaid', ?, false, NOW(), NOW())"
341	    )
342	    .bind(&merged_id).bind(owner_id.as_ref().unwrap()).bind(&merged_number).bind(period.as_ref().unwrap())
343	    .bind(&addr).bind(total)
344	    .execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
345	
346	    for item in &all_items {
347	        sqlx::query(
348	            "INSERT INTO order_line_items (id, order_id, publication_title, series_name, quantity, unit_price, line_total) VALUES (?, ?, ?, ?, ?, ?, ?)"
349	        )
350	        .bind(&item.id).bind(&merged_id).bind(&item.publication_title).bind(&item.series_name)
351	        .bind(item.quantity).bind(item.unit_price).bind(item.line_total)
352	        .execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
353	    }
354	
355	    // Mark originals as merged
356	    for oid in &req.order_ids {
357	        sqlx::query("UPDATE orders SET status = 'merged', parent_order_id = ?, updated_at = NOW() WHERE id = ?")
358	            .bind(&merged_id).bind(oid).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
359	    }
360	
361	    let order = Order {
362	        id: merged_id, user_id: owner_id.unwrap(), order_number: merged_number,
363	        subscription_period: period.unwrap(), shipping_address_id: addr,
364	        status: "pending".to_string(), payment_status: "unpaid".to_string(),
365	        total_amount: total, parent_order_id: None, is_flagged: false, flag_reason: None,
366	        created_at: None, updated_at: None,
367	    };
368	
369	    Ok(Json(OrderWithItems { order, line_items: all_items }))
370	}
