73	/// Run SQL migrations — fail-fast on errors (panics on critical failures).
74	async fn run_migrations(pool: &DbPool) {
75	    let migrations = include_str!("migrations/001_initial.sql");
76	    for statement in migrations.split(';') {
77	        let trimmed = statement.trim();
78	        if !trimmed.is_empty() {
79	            match sqlx::query(trimmed).execute(pool).await {
80	                Ok(_) => {}
81	                Err(e) => {
82	                    let err_str = e.to_string();
83	                    // "already exists" is expected on re-runs — safe to skip
84	                    if err_str.contains("already exists") || err_str.contains("Duplicate") {
85	                        log::debug!("Migration skip (idempotent): {}", err_str);
86	                    } else {
87	                        panic!("FATAL: Migration failed — {}", err_str);
88	                    }
89	                }
90	            }
91	        }
92	    }
93	    log::info!("Database migrations completed");
94	
95	    let seed = include_str!("migrations/002_seed.sql");
96	    for statement in seed.split(';') {
97	        let trimmed = statement.trim();
98	        if !trimmed.is_empty() {
99	            match sqlx::query(trimmed).execute(pool).await {
100	                Ok(_) => {}
101	                Err(e) => {
102	                    let err_str = e.to_string();
103	                    if err_str.contains("Duplicate") {
104	                        log::debug!("Seed skip (idempotent): {}", err_str);
105	                    } else {
106	                        panic!("FATAL: Seed data failed — {}", err_str);
107	                    }
108	                }
109	            }
110	        }
111	    }
112	    log::info!("Seed data applied");
113	
114	    // If ADMIN_PASSWORD is set, re-hash and apply to all seeded accounts
115	    if let Ok(admin_pass) = std::env::var("ADMIN_PASSWORD") {
116	        match bcrypt::hash(&admin_pass, bcrypt::DEFAULT_COST) {
117	            Ok(hash) => {
118	                let _ = sqlx::query(
119	                    "UPDATE users SET password_hash = ? WHERE username IN ('admin', 'moderator', 'host', 'clerk', 'member')"
120	                )
121	                .bind(&hash)
122	                .execute(pool)
123	                .await;
124	                log::info!("Seeded user credentials updated from ADMIN_PASSWORD");
125	            }
126	            Err(e) => log::warn!("Failed to hash ADMIN_PASSWORD: {}", e),
127	        }
128	    }
129	}
