93	/// File-type allowlist check
94	pub fn validate_file_type(filename: &str, magic_bytes: &[u8]) -> Result<String, String> {
95	    let ext = filename.rsplit('.').next().unwrap_or("").to_lowercase();
96	
97	    let allowed = match ext.as_str() {
98	        "pdf" => magic_bytes.starts_with(b"%PDF"),
99	        "docx" => magic_bytes.starts_with(&[0x50, 0x4B, 0x03, 0x04]),
100	        "png" => magic_bytes.starts_with(&[0x89, 0x50, 0x4E, 0x47]),
101	        "jpg" | "jpeg" => magic_bytes.starts_with(&[0xFF, 0xD8, 0xFF]),
102	        _ => return Err(format!("File type '{}' not allowed. Allowed: PDF, DOCX, PNG, JPG", ext)),
103	    };
104	
105	    if !allowed {
106	        return Err(format!("File signature does not match extension '{}'", ext));
107	    }
108	
109	    Ok(ext)
110	}
