4	
5	const BACKEND_URL: &str = "http://localhost:8000";
6	
7	fn auth_header() -> Option<String> {
8	    LocalStorage::get::<String>("auth_token")
9	        .ok()
10	        .map(|t| format!("Bearer {}", t))
11	}
12	
13	pub async fn get<T: DeserializeOwned>(path: &str) -> Result<T, String> {
14	    let url = format!("{}{}", BACKEND_URL, path);
15	    let mut req = Request::get(&url);
16	
17	    if let Some(token) = auth_header() {
18	        req = req.header("Authorization", &token);
19	    }
20	
21	    let resp = req.send().await.map_err(|e| e.to_string())?;
22	
23	    if resp.ok() {
24	        resp.json::<T>().await.map_err(|e| e.to_string())
25	    } else {
26	        Err(format!("Request failed with status: {}", resp.status()))
27	    }
28	}
29	
30	pub async fn post<T: DeserializeOwned, B: Serialize>(path: &str, body: &B) -> Result<T, String> {
31	    let url = format!("{}{}", BACKEND_URL, path);
32	    let mut req = Request::post(&url)
33	        .header("Content-Type", "application/json");
34	
35	    if let Some(token) = auth_header() {
36	        req = req.header("Authorization", &token);
37	    }
38	
39	    let body_str = serde_json::to_string(body).map_err(|e| e.to_string())?;
40	    let resp = req.body(body_str).unwrap().send().await.map_err(|e| e.to_string())?;
41	
42	    if resp.ok() {
43	        resp.json::<T>().await.map_err(|e| e.to_string())
44	    } else {
45	        Err(format!("Request failed with status: {}", resp.status()))
46	    }
47	}
