9	#[post("/", data = "<req>")]
10	pub async fn create_payment(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<CreatePaymentRequest>) -> Result<Json<Payment>, Status> {
11	    user.require_permission("payments.manage")?;
12	
13	    let valid_methods = ["cash", "check", "on_account"];
14	    if !valid_methods.contains(&req.payment_method.as_str()) {
15	        return Err(Status::BadRequest);
16	    }
17	
18	    let valid_types = ["charge", "hold", "release", "refund"];
19	    if !valid_types.contains(&req.transaction_type.as_str()) {
20	        return Err(Status::BadRequest);
21	    }
22	
23	    // Idempotency check — if this key already exists, return the existing payment
24	    let existing = sqlx::query_as::<_, (String, String, String, String, f64, String, Option<String>, String, Option<String>, Option<String>, Option<String>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
25	        "SELECT id, order_id, idempotency_key, payment_method, amount, transaction_type, reference_payment_id, status, check_number, notes, processed_by, created_at, updated_at FROM payments WHERE idempotency_key = ?"
26	    )
27	    .bind(&req.idempotency_key)
28	    .fetch_optional(pool.inner())
29	    .await
30	    .map_err(|_| Status::InternalServerError)?;
31	
32	    if let Some((id, oid, ik, pm, amount, tt, rpi, status, cn, notes, pb, ca, ua)) = existing {
33	        return Ok(Json(Payment {
34	            id, order_id: oid, idempotency_key: ik, payment_method: pm, amount,
35	            transaction_type: tt, reference_payment_id: rpi, status, check_number: cn,
36	            notes, processed_by: pb, created_at: ca, updated_at: ua,
37	        }));
38	    }
39	
40	    let id = Uuid::new_v4().to_string();
41	    let status = match req.transaction_type.as_str() {
42	        "hold" => "held",
43	        "charge" => "completed",
44	        "release" => "released",
45	        "refund" => "refunded",
46	        _ => "pending",
47	    };
48	
49	    sqlx::query(
50	        "INSERT INTO payments (id, order_id, idempotency_key, payment_method, amount, transaction_type, reference_payment_id, status, check_number, notes, processed_by, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())"
51	    )
52	    .bind(&id).bind(&req.order_id).bind(&req.idempotency_key).bind(&req.payment_method)
53	    .bind(req.amount).bind(&req.transaction_type).bind(&req.reference_payment_id)
54	    .bind(status).bind(&req.check_number).bind(&req.notes).bind(&user.user_id)
55	    .execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
56	
57	    // Update order payment status
58	    match req.transaction_type.as_str() {
59	        "charge" => {
60	            sqlx::query("UPDATE orders SET payment_status = 'paid', updated_at = NOW() WHERE id = ?")
61	                .bind(&req.order_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
62	        }
63	        "hold" => {
64	            sqlx::query("UPDATE orders SET payment_status = 'held', updated_at = NOW() WHERE id = ?")
65	                .bind(&req.order_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
66	        }
67	        "refund" => {
68	            sqlx::query("UPDATE orders SET payment_status = 'refunded', updated_at = NOW() WHERE id = ?")
69	                .bind(&req.order_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
70	        }
71	        _ => {}
72	    }
73	
74	    Ok(Json(Payment {
75	        id, order_id: req.order_id.clone(), idempotency_key: req.idempotency_key.clone(),
76	        payment_method: req.payment_method.clone(), amount: req.amount,
77	        transaction_type: req.transaction_type.clone(), reference_payment_id: req.reference_payment_id.clone(),
78	        status: status.to_string(), check_number: req.check_number.clone(),
79	        notes: req.notes.clone(), processed_by: Some(user.user_id),
80	        created_at: None, updated_at: None,
81	    }))
82	}
