84	#[post("/refund", data = "<req>")]
85	pub async fn refund_payment(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<RefundPaymentRequest>) -> Result<Json<Payment>, Status> {
86	    user.require_permission("payments.manage")?;
87	
88	    // Idempotency check
89	    let existing = sqlx::query_scalar::<_, String>("SELECT id FROM payments WHERE idempotency_key = ?")
90	        .bind(&req.idempotency_key).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
91	
92	    if let Some(existing_id) = existing {
93	        // Idempotent: return the existing refund payment (HTTP 200, not a double-charge)
94	        let existing_row = sqlx::query_as::<_, (String, String, String, String, f64, String, Option<String>, String, Option<String>, Option<String>, Option<String>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
95	            "SELECT id, order_id, idempotency_key, payment_method, amount, transaction_type, reference_payment_id, status, check_number, notes, processed_by, created_at, updated_at FROM payments WHERE id = ?"
96	        ).bind(&existing_id).fetch_one(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
97	        let (id, oid, ik, pm, amount, tt, rpi, status, cn, notes, pb, ca, ua) = existing_row;
98	        return Ok(Json(Payment {
99	            id, order_id: oid, idempotency_key: ik, payment_method: pm, amount,
100	            transaction_type: tt, reference_payment_id: rpi, status, check_number: cn,
101	            notes, processed_by: pb, created_at: ca, updated_at: ua,
102	        }));
103	    }
104	
105	    // Get original payment
106	    let orig = sqlx::query_as::<_, (String, String, f64, String)>(
107	        "SELECT id, order_id, amount, status FROM payments WHERE id = ?"
108	    )
109	    .bind(&req.original_payment_id).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
110	
111	    match orig {
112	        Some((orig_id, order_id, orig_amount, orig_status)) => {
113	            if orig_status != "completed" && orig_status != "held" {
114	                return Err(Status::BadRequest);
115	            }
116	            if req.amount > orig_amount {
117	                return Err(Status::BadRequest);
118	            }
119	
120	            let id = Uuid::new_v4().to_string();
121	
122	            sqlx::query(
123	                "INSERT INTO payments (id, order_id, idempotency_key, payment_method, amount, transaction_type, reference_payment_id, status, notes, processed_by, created_at, updated_at) VALUES (?, ?, ?, 'on_account', ?, 'refund', ?, 'refunded', ?, ?, NOW(), NOW())"
124	            )
125	            .bind(&id).bind(&order_id).bind(&req.idempotency_key).bind(req.amount)
126	            .bind(&orig_id).bind(&req.reason).bind(&user.user_id)
127	            .execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
128	
129	            // Update order payment status
130	            if (req.amount - orig_amount).abs() < 0.01 {
131	                sqlx::query("UPDATE orders SET payment_status = 'refunded', updated_at = NOW() WHERE id = ?")
132	                    .bind(&order_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
133	            } else {
134	                sqlx::query("UPDATE orders SET payment_status = 'partial_refund', updated_at = NOW() WHERE id = ?")
135	                    .bind(&order_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
136	            }
137	
138	            Ok(Json(Payment {
139	                id, order_id, idempotency_key: req.idempotency_key.clone(),
140	                payment_method: "on_account".to_string(), amount: req.amount,
141	                transaction_type: "refund".to_string(), reference_payment_id: Some(orig_id),
142	                status: "refunded".to_string(), check_number: None,
143	                notes: req.reason.clone(), processed_by: Some(user.user_id),
144	                created_at: None, updated_at: None,
145	            }))
146	        }
147	        None => Err(Status::NotFound),
148	    }
149	}
