176	#[get("/reconciliation-report")]
177	pub async fn get_reconciliation_report(pool: &State<DbPool>, user: AuthenticatedUser) -> Result<Json<serde_json::Value>, Status> {
178	    user.require_permission("admin.dashboard")?;
179	
180	    let total_charges = sqlx::query_scalar::<_, f64>(
181	        "SELECT COALESCE(SUM(amount), 0) FROM payments WHERE transaction_type = 'charge' AND status = 'completed'"
182	    )
183	    .fetch_one(pool.inner()).await.unwrap_or(0.0);
184	
185	    let total_holds = sqlx::query_scalar::<_, f64>(
186	        "SELECT COALESCE(SUM(amount), 0) FROM payments WHERE transaction_type = 'hold' AND status = 'held'"
187	    )
188	    .fetch_one(pool.inner()).await.unwrap_or(0.0);
189	
190	    let total_refunds = sqlx::query_scalar::<_, f64>(
191	        "SELECT COALESCE(SUM(amount), 0) FROM payments WHERE transaction_type = 'refund'"
192	    )
193	    .fetch_one(pool.inner()).await.unwrap_or(0.0);
194	
195	    let expected_balance = total_charges - total_refunds;
196	    let actual_balance = total_charges + total_holds - total_refunds;
197	    let discrepancy = actual_balance - expected_balance;
198	
199	    Ok(Json(serde_json::json!({
200	        "report_date": chrono::Utc::now().format("%Y-%m-%d").to_string(),
201	        "total_charges": total_charges,
202	        "total_holds": total_holds,
203	        "total_refunds": total_refunds,
204	        "expected_balance": expected_balance,
205	        "actual_balance": actual_balance,
206	        "discrepancy": discrepancy
207	    })))
208	}
