236	/// Generate and persist a reconciliation report for today. Idempotent — skips if today's report exists.
237	pub async fn generate_reconciliation_report(pool: &crate::DbPool) {
238	    let today = chrono::Utc::now().format("%Y-%m-%d").to_string();
239	
240	    // Skip if already generated today
241	    let exists: i64 = sqlx::query_scalar("SELECT COUNT(*) FROM reconciliation_reports WHERE report_date = ?")
242	        .bind(&today)
243	        .fetch_one(pool)
244	        .await
245	        .unwrap_or(0);
246	
247	    if exists > 0 {
248	        log::debug!("Reconciliation report for {} already exists, skipping", today);
249	        return;
250	    }
251	
252	    let expected_balance: f64 = sqlx::query_scalar(
253	        "SELECT COALESCE(CAST(SUM(total_amount) AS DOUBLE), 0) FROM orders WHERE payment_status != 'refunded'"
254	    )
255	    .fetch_one(pool).await.unwrap_or(0.0);
256	
257	    let actual_balance: f64 = sqlx::query_scalar(
258	        "SELECT COALESCE(CAST(SUM(CASE WHEN transaction_type = 'charge' THEN amount WHEN transaction_type = 'refund' THEN -amount ELSE 0 END) AS DOUBLE), 0) FROM payments WHERE status IN ('completed', 'refunded')"
259	    )
260	    .fetch_one(pool).await.unwrap_or(0.0);
261	
262	    let discrepancy = actual_balance - expected_balance;
263	    let id = uuid::Uuid::new_v4().to_string();
264	
265	    let _ = sqlx::query(
266	        "INSERT INTO reconciliation_reports (id, report_date, expected_balance, actual_balance, discrepancy, details, generated_at) VALUES (?, ?, ?, ?, ?, ?, NOW())"
267	    )
268	    .bind(&id)
269	    .bind(&today)
270	    .bind(expected_balance)
271	    .bind(actual_balance)
272	    .bind(discrepancy)
273	    .bind(serde_json::json!({
274	        "generated_by": "nightly_scheduler",
275	        "note": "Auto-generated daily reconciliation report"
276	    }).to_string())
277	    .execute(pool)
278	    .await;
279	
280	    log::info!("Reconciliation report generated for {}: expected={:.2}, actual={:.2}, discrepancy={:.2}", today, expected_balance, actual_balance, discrepancy);
281	}
