1	use gloo_storage::{LocalStorage, Storage};
2	use serde::{Deserialize, Serialize};
3	
4	use super::api;
5	
6	#[derive(Debug, Clone, Serialize, Deserialize)]
7	pub struct UserInfo {
8	    pub id: String,
9	    pub username: String,
10	    pub email: String,
11	    pub first_name: String,
12	    pub last_name: String,
13	    pub role: String,
14	    pub is_active: bool,
15	    pub invoice_title: Option<String>,
16	    pub notify_submissions: bool,
17	    pub notify_orders: bool,
18	    pub notify_reviews: bool,
19	    pub notify_cases: bool,
20	}
21	
22	#[derive(Debug, Serialize, Deserialize)]
23	struct LoginRequest {
24	    username: String,
25	    password: String,
26	}
27	
28	#[derive(Debug, Serialize, Deserialize)]
29	struct LoginResponse {
30	    token: String,
31	    user: UserInfo,
32	}
33	
34	#[derive(Debug, Clone, Serialize)]
35	pub struct RegisterData {
36	    pub username: String,
37	    pub email: String,
38	    pub password: String,
39	    pub first_name: String,
40	    pub last_name: String,
41	    pub role: String,
42	}
43	
44	pub async fn login(username: &str, password: &str) -> Result<UserInfo, String> {
45	    let req = LoginRequest {
46	        username: username.to_string(),
47	        password: password.to_string(),
48	    };
49	
50	    let resp: LoginResponse = api::post("/api/auth/login", &req).await?;
51	
52	    LocalStorage::set("auth_token", &resp.token).map_err(|e| e.to_string())?;
53	    LocalStorage::set("current_user", &resp.user).map_err(|e| e.to_string())?;
54	
55	    Ok(resp.user)
56	}
57	
58	/// Admin-provisioned account creation.
59	pub async fn register(data: &RegisterData) -> Result<UserInfo, String> {
60	    let resp: LoginResponse = api::post("/api/auth/provision", data).await?;
61	
62	    LocalStorage::set("auth_token", &resp.token).map_err(|e| e.to_string())?;
63	    LocalStorage::set("current_user", &resp.user).map_err(|e| e.to_string())?;
64	
65	    Ok(resp.user)
66	}
67	
68	pub fn get_current_user() -> Option<UserInfo> {
69	    LocalStorage::get::<UserInfo>("current_user").ok()
70	}
71	
72	pub fn get_token() -> Option<String> {
73	    LocalStorage::get::<String>("auth_token").ok()
74	}
75	
76	pub async fn logout() {
77	    // Invalidate server-side session before clearing local state
78	    let _ = api::post_no_body("/api/auth/logout").await;
79	    let _ = LocalStorage::delete("auth_token");
80	    let _ = LocalStorage::delete("current_user");
81	}
82	
83	pub fn is_authenticated() -> bool {
84	    get_token().is_some()
85	}
