11	#[post("/", data = "<req>")]
12	pub async fn create_review(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<CreateReviewRequest>) -> Result<Json<Review>, Status> {
13	    if req.rating < 1 || req.rating > 5 {
14	        return Err(Status::BadRequest);
15	    }
16	    if req.title.len() > 120 {
17	        return Err(Status::UnprocessableEntity);
18	    }
19	
20	    let order_check = sqlx::query_as::<_, (String, String)>(
21	        "SELECT user_id, status FROM orders WHERE id = ?"
22	    )
23	    .bind(&req.order_id)
24	    .fetch_optional(pool.inner())
25	    .await
26	    .map_err(|_| Status::InternalServerError)?;
27	
28	    match order_check {
29	        Some((uid, status)) => {
30	            if uid != user.user_id { return Err(Status::Forbidden); }
31	            if status != "delivered" { return Err(Status::BadRequest); }
32	        }
33	        None => return Err(Status::NotFound),
34	    }
35	
36	    let existing = sqlx::query_scalar::<_, i64>(
37	        "SELECT COUNT(*) FROM reviews WHERE order_id = ? AND user_id = ? AND is_followup = false"
38	    )
39	    .bind(&req.order_id).bind(&user.user_id)
40	    .fetch_one(pool.inner()).await.unwrap_or(0);
41	
42	    if existing > 0 {
43	        return Err(Status::Conflict);
44	    }
45	
46	    let id = Uuid::new_v4().to_string();
47	
48	    sqlx::query(
49	        "INSERT INTO reviews (id, order_id, line_item_id, user_id, rating, title, body, is_followup, parent_review_id, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, false, NULL, NOW(), NOW())"
50	    )
51	    .bind(&id).bind(&req.order_id).bind(&req.line_item_id).bind(&user.user_id)
52	    .bind(req.rating).bind(&req.title).bind(&req.body)
53	    .execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
54	
55	    Ok(Json(Review {
56	        id, order_id: req.order_id.clone(), line_item_id: req.line_item_id.clone(),
57	        user_id: user.user_id, rating: req.rating, title: req.title.clone(),
58	        body: req.body.clone(), is_followup: false, parent_review_id: None,
59	        created_at: None, updated_at: None,
60	    }))
61	}
