63	#[post("/followup", data = "<req>")]
64	pub async fn create_followup(pool: &State<DbPool>, user: AuthenticatedUser, req: Json<CreateFollowupRequest>) -> Result<Json<Review>, Status> {
65	    if req.rating < 1 || req.rating > 5 {
66	        return Err(Status::BadRequest);
67	    }
68	
69	    let parent = sqlx::query_as::<_, (String, String, String, bool, Option<chrono::NaiveDateTime>)>(
70	        "SELECT id, order_id, user_id, is_followup, created_at FROM reviews WHERE id = ?"
71	    )
72	    .bind(&req.parent_review_id)
73	    .fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
74	
75	    match parent {
76	        Some((pid, order_id, parent_uid, is_fu, created_at)) => {
77	            if parent_uid != user.user_id { return Err(Status::Forbidden); }
78	            if is_fu { return Err(Status::BadRequest); }
79	
80	            if let Some(ca) = created_at {
81	                let deadline = ca + Duration::days(models::FOLLOWUP_WINDOW_DAYS);
82	                if chrono::Utc::now().naive_utc() > deadline {
83	                    return Err(Status::Gone);
84	                }
85	            }
86	
87	            let existing_fu = sqlx::query_scalar::<_, i64>(
88	                "SELECT COUNT(*) FROM reviews WHERE parent_review_id = ? AND is_followup = true"
89	            )
90	            .bind(&pid).fetch_one(pool.inner()).await.unwrap_or(0);
91	
92	            if existing_fu > 0 {
93	                return Err(Status::Conflict);
94	            }
95	
96	            let id = Uuid::new_v4().to_string();
97	
98	            sqlx::query(
99	                "INSERT INTO reviews (id, order_id, line_item_id, user_id, rating, title, body, is_followup, parent_review_id, created_at, updated_at) VALUES (?, ?, NULL, ?, ?, ?, ?, true, ?, NOW(), NOW())"
100	            )
101	            .bind(&id).bind(&order_id).bind(&user.user_id)
102	            .bind(req.rating).bind(&req.title).bind(&req.body).bind(&pid)
103	            .execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
104	
105	            Ok(Json(Review {
106	                id, order_id, line_item_id: None, user_id: user.user_id,
107	                rating: req.rating, title: req.title.clone(), body: req.body.clone(),
108	                is_followup: true, parent_review_id: Some(pid),
109	                created_at: None, updated_at: None,
110	            }))
111	        }
112	        None => Err(Status::NotFound),
113	    }
114	}
