117	#[get("/")]
118	pub async fn list_reviews(pool: &State<DbPool>, user: AuthenticatedUser) -> Result<Json<Vec<Review>>, Status> {
119	    let rows = if user.is_privileged() {
120	        sqlx::query_as::<_, (String, String, Option<String>, String, i32, String, String, bool, Option<String>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
121	            "SELECT id, order_id, line_item_id, user_id, rating, title, body, is_followup, parent_review_id, created_at, updated_at FROM reviews ORDER BY created_at DESC LIMIT 200"
122	        )
123	        .fetch_all(pool.inner()).await
124	    } else {
125	        sqlx::query_as::<_, (String, String, Option<String>, String, i32, String, String, bool, Option<String>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
126	            "SELECT id, order_id, line_item_id, user_id, rating, title, body, is_followup, parent_review_id, created_at, updated_at FROM reviews WHERE user_id = ? ORDER BY created_at DESC"
127	        )
128	        .bind(&user.user_id)
129	        .fetch_all(pool.inner()).await
130	    }.map_err(|_| Status::InternalServerError)?;
131	
132	    let reviews: Vec<Review> = rows.into_iter().map(|(id, oid, lid, uid, rating, title, body, fu, prid, ca, ua)| {
133	        Review { id, order_id: oid, line_item_id: lid, user_id: uid, rating, title, body, is_followup: fu, parent_review_id: prid, created_at: ca, updated_at: ua }
134	    }).collect();
135	
136	    Ok(Json(reviews))
137	}
