139	/// Get single review — IDOR enforced: owner, or order owner, or staff/admin.
140	#[get("/<review_id>")]
141	pub async fn get_review(pool: &State<DbPool>, user: AuthenticatedUser, review_id: String) -> Result<Json<Review>, Status> {
142	    let row = sqlx::query_as::<_, (String, String, Option<String>, String, i32, String, String, bool, Option<String>, Option<chrono::NaiveDateTime>, Option<chrono::NaiveDateTime>)>(
143	        "SELECT id, order_id, line_item_id, user_id, rating, title, body, is_followup, parent_review_id, created_at, updated_at FROM reviews WHERE id = ?"
144	    )
145	    .bind(&review_id).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
146	
147	    match row {
148	        Some((id, oid, lid, uid, rating, title, body, fu, prid, ca, ua)) => {
149	            // IDOR: must be the review author, the order owner, or privileged
150	            let is_privileged = user.is_privileged();
151	            let is_review_owner = uid == user.user_id;
152	            if !is_review_owner && !is_privileged {
153	                // Check if requester owns the order
154	                let order_owner = sqlx::query_scalar::<_, String>("SELECT user_id FROM orders WHERE id = ?")
155	                    .bind(&oid).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
156	                if order_owner.as_deref() != Some(&user.user_id) {
157	                    return Err(Status::Forbidden);
158	                }
159	            }
160	
161	            Ok(Json(Review { id, order_id: oid, line_item_id: lid, user_id: uid, rating, title, body, is_followup: fu, parent_review_id: prid, created_at: ca, updated_at: ua }))
162	        }
163	        None => Err(Status::NotFound),
164	    }
165	}
