167	#[post("/<review_id>/images", data = "<req>")]
168	pub async fn add_review_image(pool: &State<DbPool>, user: AuthenticatedUser, review_id: String, req: Json<AddReviewImageRequest>) -> Result<Status, Status> {
169	    let owner = sqlx::query_scalar::<_, String>("SELECT user_id FROM reviews WHERE id = ?")
170	        .bind(&review_id).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
171	
172	    match owner {
173	        Some(uid) if uid == user.user_id => {}
174	        Some(_) => return Err(Status::Forbidden),
175	        None => return Err(Status::NotFound),
176	    }
177	
178	    let count = sqlx::query_scalar::<_, i64>("SELECT COUNT(*) FROM review_images WHERE review_id = ?")
179	        .bind(&review_id).fetch_one(pool.inner()).await.unwrap_or(0);
180	
181	    if count >= models::MAX_REVIEW_IMAGES as i64 {
182	        return Err(Status::UnprocessableEntity);
183	    }
184	
185	    let file_data = base64::Engine::decode(&base64::engine::general_purpose::STANDARD, &req.file_data)
186	        .map_err(|_| Status::BadRequest)?;
187	
188	    if file_data.len() as u64 > models::MAX_REVIEW_IMAGE_SIZE {
189	        return Err(Status::PayloadTooLarge);
190	    }
191	
192	    // Validate file type and magic bytes — only PNG and JPG allowed for review images
193	    let magic = if file_data.len() >= 8 { &file_data[..8] } else { &file_data };
194	    let ext = req.file_name.rsplit('.').next().unwrap_or("").to_lowercase();
195	    let valid_image = match ext.as_str() {
196	        "png" => magic.starts_with(&[0x89, 0x50, 0x4E, 0x47]),
197	        "jpg" | "jpeg" => magic.starts_with(&[0xFF, 0xD8, 0xFF]),
198	        _ => false,
199	    };
200	    if !valid_image {
201	        return Err(Status::UnsupportedMediaType);
202	    }
203	
204	    // Compute SHA-256 hash for integrity
205	    use sha2::{Digest, Sha256};
206	    let mut hasher = Sha256::new();
207	    hasher.update(&file_data);
208	    let file_hash = hex::encode(hasher.finalize());
209	
210	    let id = Uuid::new_v4().to_string();
211	    let file_path = format!("uploads/reviews/{}/{}", review_id, req.file_name);
212	
213	    sqlx::query(
214	        "INSERT INTO review_images (id, review_id, file_name, file_path, file_size, file_type, file_hash, image_data, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, NOW())"
215	    )
216	    .bind(&id).bind(&review_id).bind(&req.file_name).bind(&file_path)
217	    .bind(file_data.len() as i64).bind(&ext).bind(&file_hash).bind(&file_data)
218	    .execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
219	
220	    Ok(Status::Created)
221	}
