81	// These endpoints manage the content governance lifecycle:
82	// submit → review → approve/reject → publish, with versioning and rollback.
83	
84	/// Submit a draft submission for review (changes status draft → submitted)
85	#[post("/items/<item_id>/submit")]
86	pub async fn submit_item(pool: &State<DbPool>, user: AuthenticatedUser, item_id: String) -> Result<Status, Status> {
87	    let row = sqlx::query_as::<_, (String, String)>(
88	        "SELECT author_id, status FROM submissions WHERE id = ?"
89	    ).bind(&item_id).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
90	
91	    match row {
92	        Some((author_id, status)) => {
93	            if author_id != user.user_id { return Err(Status::Forbidden); }
94	            if status != "draft" && status != "revision_requested" {
95	                return Err(Status::Conflict);
96	            }
97	            sqlx::query("UPDATE submissions SET status = 'submitted', updated_at = NOW() WHERE id = ?")
98	                .bind(&item_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
99	            Ok(Status::Ok)
100	        }
101	        None => Err(Status::NotFound),
102	    }
103	}
