105	/// Staff/admin approves content (submitted/in_review → accepted)
106	#[post("/items/<item_id>/approve")]
107	pub async fn approve_item(pool: &State<DbPool>, user: AuthenticatedUser, item_id: String) -> Result<Status, Status> {
108	    user.require_permission("submissions.review")?;
109	
110	    let status = sqlx::query_scalar::<_, String>("SELECT status FROM submissions WHERE id = ?")
111	        .bind(&item_id).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
112	
113	    match status {
114	        Some(s) if s == "submitted" || s == "in_review" || s == "blocked" => {
115	            sqlx::query("UPDATE submissions SET status = 'accepted', updated_at = NOW() WHERE id = ?")
116	                .bind(&item_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
117	
118	            let _ = sqlx::query("INSERT INTO audit_log (id, user_id, action, target_type, target_id, details, created_at) VALUES (?, ?, 'content_approved', 'submission', ?, 'Content item approved', NOW())")
119	                .bind(Uuid::new_v4().to_string()).bind(&user.user_id).bind(&item_id)
120	                .execute(pool.inner()).await;
121	            Ok(Status::Ok)
122	        }
123	        Some(_) => Err(Status::Conflict),
124	        None => Err(Status::NotFound),
125	    }
126	}
