171	/// Rollback to a previous version (resets current_version)
172	#[post("/items/<item_id>/rollback/<version_number>")]
173	pub async fn rollback_version(pool: &State<DbPool>, user: AuthenticatedUser, item_id: String, version_number: i32) -> Result<Status, Status> {
174	    let row = sqlx::query_as::<_, (String, String)>(
175	        "SELECT author_id, status FROM submissions WHERE id = ?"
176	    ).bind(&item_id).fetch_optional(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
177	
178	    match row {
179	        Some((author_id, _status)) => {
180	            user.require_owner_or_privileged(&author_id)?;
181	
182	            // Verify the target version exists
183	            let exists = sqlx::query_scalar::<_, i64>(
184	                "SELECT COUNT(*) FROM submission_versions WHERE submission_id = ? AND version_number = ?"
185	            ).bind(&item_id).bind(version_number).fetch_one(pool.inner()).await.unwrap_or(0);
186	
187	            if exists == 0 { return Err(Status::NotFound); }
188	
189	            sqlx::query("UPDATE submissions SET current_version = ?, status = 'draft', updated_at = NOW() WHERE id = ?")
190	                .bind(version_number).bind(&item_id).execute(pool.inner()).await.map_err(|_| Status::InternalServerError)?;
191	
192	            let _ = sqlx::query("INSERT INTO audit_log (id, user_id, action, target_type, target_id, details, created_at) VALUES (?, ?, 'content_rollback', 'submission', ?, ?, NOW())")
193	                .bind(Uuid::new_v4().to_string()).bind(&user.user_id).bind(&item_id)
194	                .bind(&format!("Rolled back to version {}", version_number))
195	                .execute(pool.inner()).await;
196	
197	            Ok(Status::Ok)
198	        }
199	        None => Err(Status::NotFound),
200	    }
201	}
