894	
895	        let content_type = resp.headers()
896	            .get("content-type")
897	            .and_then(|v| v.to_str().ok())
898	            .unwrap_or("");
899	        assert!(
900	            content_type.contains("image/png"),
901	            "Download must return image/png, got: {}",
