904	
905	        let body = resp.bytes().await.unwrap();
906	        // PNG signature must still be present (watermark inserted AFTER signature)
907	        assert!(
908	            body.len() >= 8 && body[0] == 0x89 && body[1] == 0x50 && body[2] == 0x4E && body[3] == 0x47,
909	            "Watermarked PNG must still have PNG signature"
910	        );
