913	    /// Simple CRC-32 for PNG test construction
914	    fn crc32(data: &[u8]) -> u32 {
915	        let mut crc: u32 = 0xFFFFFFFF;
916	        for &byte in data {
917	            crc ^= byte as u32;
918	            for _ in 0..8 {
919	                if crc & 1 != 0 { crc = (crc >> 1) ^ 0xEDB88320; } else { crc >>= 1; }
920	            }
921	        }
922	        !crc
923	    }
